import{_ as r,a as i,b as s,m as o,d as e,i as t}from"./chunks/framework.DhA78p7M.js";const v=JSON.parse('{"title":"Projects","description":"","frontmatter":{"title":"Projects"},"headers":[],"relativePath":"projects.md","filePath":"projects.md"}'),c={name:"projects.md"};function n(d,a,l,h,p,m){return i(),s("div",null,[...a[0]||(a[0]=[o('<h2 id="notable-projects" tabindex="-1">Notable Projects <a class="header-anchor" href="#notable-projects" aria-label="Permalink to “Notable Projects”">​</a></h2><div class="project-card"><div class="project-header"><h3><a href="https://github.com/arghunter/clEar" target="_blank">clEar</a></h3><a href="/blogs/clear">Writeup</a></div><p>Glasses-based beamforming hearing aids using Golomb-spaced microphone arrays and a custom MSMVDR algorithm. 71% STOI increase, 9.9 dB SNR improvement. ISEF Grand Award, CSEF First Place.</p></div><div class="project-card"><div class="project-header"><h3><a href="https://github.com/arghunter/Supermic-tt08" target="_blank">Supermic+more</a></h3><a href="/blogs/supermic">Writeup</a></div><p>PDM bitstream signal processing ASICs fabricated on the Skywater 130nm CMOS process via Tiny Tapeout 8. Eight chips targeting beamforming and audio DSP for hearing aids.</p></div><div class="project-card"><div class="project-header"><h3><a href="https://isef.net/project/ebed041-novel-pdm-operators-for-efficient-beamforming"> PDM Bitstream Operators for Efficient Beamforming</a></h3><span class="subtext">ISEF 2nd Award Internationally</span></div><p>Leveraged microphone PDM bitstreams to achieve a 250× runtime improvement in beamforming while lowering power demands. Custom-designed PCB hardware and FPGA-based acoustic camera.</p></div><div class="project-card"><div class="project-header"><h3><a href="https://github.com/arghunter/Potentiostat" target="_blank">Potentiostat</a></h3></div><p>18-channel high-speed potentiostat for rapid blood tests and chemical detection. Built with the UC Berkeley Nanotechnology Lab. Includes FPGA firmware and C# driver for a 256-channel electrochemical camera.</p></div><div class="project-card"><div class="project-header"><h3><a href="https://github.com/arghunter/FlamProtect" target="_blank">FlamProtect</a></h3></div><p>Mathematical wildfire models and genetic algorithms to optimize firebreak placement for wildfire containment.</p></div><div style="height:20px;"></div><h2 id="asic-designs" tabindex="-1">ASIC Designs <a class="header-anchor" href="#asic-designs" aria-label="Permalink to “ASIC Designs”">​</a></h2><div class="project-card"><div class="project-header"><h3><a href="https://github.com/arghunter/16-Mic-Beamformer-Verilog" target="_blank">16-Microphone Beamformer</a></h3></div><p>16-channel PDM beamformer with DDR input and I2S output, fabricated on Tiny Tapeout 8.</p></div><div class="project-card"><div class="project-header"><h3><a href="https://github.com/arghunter/Customizable-PDM-Pitch-Filter-ASIC" target="_blank">Programmable PDM Pitch Filter</a></h3></div><p>Narrowband notch filter exploiting PDM&#39;s high time resolution to remove specific frequencies from an audio stream.</p></div><div class="project-card"><div class="project-header"><h3><a href="https://github.com/arghunter/Customizable-PDM-Cross-Correlator-ASIC" target="_blank">PDM Cross/Auto Correlator</a></h3></div><p>Computes delay via cross-correlation on PDM bitstreams for direction-of-arrival and pitch identification.</p></div><div style="height:20px;"></div><h2 id="mit-open-compute-lab" tabindex="-1">MIT Open Compute Lab <a class="header-anchor" href="#mit-open-compute-lab" aria-label="Permalink to “MIT Open Compute Lab”">​</a></h2><div class="project-card"><div class="project-header"><h3>DNN Accelerators</h3></div><p>Custom accelerators for deep neural networks demonstrating PDM, Ternary, and INT8 inference.</p></div><div class="project-card"><div class="project-header"><h3>RV32-IM Pipelined CPU</h3></div><p>Custom RISC-V CPU with pipelined design. Compiled and ran Pong over VGA.</p></div><div class="project-card"><div class="project-header"><h3>FPGA Server Cluster</h3><span class="subtext">In progress</span></div><p>Custom FPGA server cluster targeting 100 Gb/s+ inter-FPGA bandwidth and &gt;1.6M logic slices.</p></div><div style="height:40px;"></div>',17),e("p",null,[e("span",{class:"newsreader"},[t('"I am always doing that which I cannot do, in order that I may learn how to do it."'),e("span",{style:{"white-space":"nowrap"}},[t(" - "),e("a",{href:"https://www.youtube.com/watch?v=6g1Yi0eSjkg",onclick:"if(window.__playMusic){window.__playMusic('6g1Yi0eSjkg','Indomitable - RWBY','Jeff Williams feat. Casey Lee Williams');return false;}"}," Pablo Picasso")])])],-1),e("div",{style:{height:"60px"}},null,-1)])])}const u=r(c,[["render",n]]);export{v as __pageData,u as default};
